// DApp Smart Contract Interaction Module using ethers.js

// Import ethers.js (assuming it's available via CDN or npm)
// <script src="https://cdn.ethers.io/lib/ethers-5.7.2.umd.min.js"></script>

class DApp {
    constructor() {
        this.provider = null;
        this.signer = null;
        this.contracts = {};
        this.transactionHistory = [];
    }

    // Initialize connection to wallet (MetaMask or other Web3 provider)
    async connectWallet() {
        try {
            if (typeof window.ethereum === 'undefined') {
                throw new Error('No Web3 wallet detected. Please install MetaMask.');
            }

            // Request account access
            await window.ethereum.request({ method: 'eth_requestAccounts' });

            this.provider = new ethers.providers.Web3Provider(window.ethereum);
            this.signer = this.provider.getSigner();

            const address = await this.signer.getAddress();
            const network = await this.provider.getNetwork();
            const balance = await this.provider.getBalance(address);

            console.log(`Connected: ${address}`);
            console.log(`Network: ${network.name} (Chain ID: ${network.chainId})`);
            console.log(`Balance: ${ethers.utils.formatEther(balance)} ETH`);

            // Listen for account and network changes
            window.ethereum.on('accountsChanged', (accounts) => {
                console.log('Account changed:', accounts[0]);
                this.signer = this.provider.getSigner();
                document.dispatchEvent(new CustomEvent('accountChanged', { detail: accounts[0] }));
            });

            window.ethereum.on('chainChanged', (chainId) => {
                console.log('Network changed:', chainId);
                window.location.reload();
            });

            return { address, network: network.name, balance: ethers.utils.formatEther(balance) };
        } catch (error) {
            console.error('Wallet connection failed:', error);
            throw error;
        }
    }

    // Load a smart contract
    loadContract(name, address, abi) {
        try {
            if (!ethers.utils.isAddress(address)) {
                throw new Error(`Invalid contract address: ${address}`);
            }

            const contract = new ethers.Contract(address, abi, this.signer || this.provider);
            this.contracts[name] = {
                instance: contract,
                address: address,
                abi: abi
            };

            console.log(`Contract "${name}" loaded at ${address}`);
            return contract;
        } catch (error) {
            console.error(`Failed to load contract "${name}":`, error);
            throw error;
        }
    }

    // Get contract instance
    getContract(name) {
        if (!this.contracts[name]) {
            throw new Error(`Contract "${name}" not found. Load it first.`);
        }
        return this.contracts[name].instance;
    }

    // Read from contract (call - no gas required)
    async readContract(contractName, methodName, params = []) {
        try {
            const contract = this.getContract(contractName);

            if (!contract[methodName]) {
                throw new Error(`Method "${methodName}" not found on contract "${contractName}"`);
            }

            const result = await contract[methodName](...params);
            console.log(`Read ${contractName}.${methodName}(${params.join(', ')}):`, result);
            return result;
        } catch (error) {
            console.error(`Read failed for ${contractName}.${methodName}:`, error);
            throw error;
        }
    }

    // Write to contract (transaction - requires gas)
    async writeContract(contractName, methodName, params = [], overrides = {}) {
        try {
            if (!this.signer) {
                throw new Error('Wallet not connected. Please connect first.');
            }

            const contract = this.getContract(contractName);

            if (!contract[methodName]) {
                throw new Error(`Method "${methodName}" not found on contract "${contractName}"`);
            }

            // Estimate gas before sending
            const gasEstimate = await contract.estimateGas[methodName](...params, overrides);
            console.log(`Estimated gas for ${methodName}: ${gasEstimate.toString()}`);

            // Add gas limit with buffer
            const txOverrides = {
                ...overrides,
                gasLimit: gasEstimate.mul(120).div(100) // 20% buffer
            };

            const tx = await contract[methodName](...params, txOverrides);
            console.log(`Transaction sent: ${tx.hash}`);

            // Store in history
            this.transactionHistory.push({
                hash: tx.hash,
                contract: contractName,
                method: methodName,
                params: params,
                timestamp: Date.now(),
                status: 'pending'
            });

            // Wait for confirmation
            const receipt = await tx.wait();
            console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

            // Update history
            const historyEntry = this.transactionHistory.find(t => t.hash === tx.hash);
            if (historyEntry) {
                historyEntry.status = receipt.status === 1 ? 'confirmed' : 'failed';
                historyEntry.blockNumber = receipt.blockNumber;
                historyEntry.gasUsed = receipt.gasUsed.toString();
            }

            return receipt;
        } catch (error) {
            console.error(`Write failed for ${contractName}.${methodName}:`, error);
            throw error;
        }
    }

    // Build a custom transaction
    async buildTransaction(to, value = '0', data = '0x', gasLimit = null) {
        try {
            if (!this.signer) {
                throw new Error('Wallet not connected.');
            }

            const from = await this.signer.getAddress();
            const nonce = await this.provider.getTransactionCount(from, 'latest');
            const feeData = await this.provider.getFeeData();

            const tx = {
                from: from,
                to: to,
                value: ethers.utils.parseEther(value),
                nonce: nonce,
                data: data,
                chainId: (await this.provider.getNetwork()).chainId
            };

            // Use EIP-1559 if supported
            if (feeData.maxFeePerGas) {
                tx.maxFeePerGas = feeData.maxFeePerGas;
                tx.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
                tx.type = 2;
            } else {
                tx.gasPrice = feeData.gasPrice;
            }

            if (gasLimit) {
                tx.gasLimit = ethers.BigNumber.from(gasLimit);
            } else {
                tx.gasLimit = await this.provider.estimateGas(tx);
            }

            return tx;
        } catch (error) {
            console.error('Failed to build transaction:', error);
            throw error;
        }
    }

    // Send a raw/custom transaction
    async sendTransaction(txParams) {
        try {
            if (!this.signer) {
                throw new Error('Wallet not connected.');
            }

            const tx = await this.signer.sendTransaction(txParams);
            console.log(`Transaction sent: ${tx.hash}`);

            this.transactionHistory.push({
                hash: tx.hash,
                to: txParams.to,
                value: txParams.value ? ethers.utils.formatEther(txParams.value) : '0',
                timestamp: Date.now(),
                status: 'pending'
            });

            const receipt = await tx.wait();
            console.log(`Transaction confirmed: ${receipt.transactionHash}`);

            const historyEntry = this.transactionHistory.find(t => t.hash === tx.hash);
            if (historyEntry) {
                historyEntry.status = receipt.status === 1 ? 'confirmed' : 'failed';
                historyEntry.blockNumber = receipt.blockNumber;
            }

            return receipt;
        } catch (error) {
            console.error('Transaction failed:', error);
            throw error;
        }
    }

    // Encode function call data
    encodeFunctionData(contractName, methodName, params = []) {
        const contractInfo = this.contracts[contractName];
        if (!contractInfo) {
            throw new Error(`Contract "${contractName}" not found.`);
        }

        const iface = new ethers.utils.Interface(contractInfo.abi);
        return iface.encodeFunctionData(methodName, params);
    }

    // Decode function result
    decodeFunctionResult(contractName, methodName, data) {
        const contractInfo = this.contracts[contractName];
        if (!contractInfo) {
            throw new Error(`Contract "${contractName}" not found.`);
        }

        const iface = new ethers.utils.Interface(contractInfo.abi);
        return iface.decodeFunctionResult(methodName, data);
    }

    // Listen to contract events
    listenToEvent(contractName, eventName, callback) {
        const contract = this.getContract(contractName);
        contract.on(eventName, (...args) => {
            const event = args[args.length - 1];
            console.log(`Event ${eventName} from ${contractName}:`, event);
            callback(...args);
        });
        console.log(`Listening for "${eventName}" events on "${contractName}"`);
    }

    // Query past events
    async queryEvents(contractName, eventName, fromBlock = 0, toBlock = 'latest') {
        const contract = this.getContract(contractName);
        const filter = contract.filters[eventName]();
        const events = await contract.queryFilter(filter, fromBlock, toBlock);
        return events;
    }

    // Get transaction history
    getTransactionHistory() {
        return [...this.transactionHistory];
    }

    // Utility: Parse Ether to Wei
    parseEther(value) {
        return ethers.utils.parseEther(value);
    }

    // Utility: Format Wei to Ether
    formatEther(value) {
        return ethers.utils.formatEther(value);
    }

    // Utility: Parse units
    parseUnits(value, decimals = 18) {
        return ethers.utils.parseUnits(value, decimals);
    }

    // Utility: Format units
    formatUnits(value, decimals = 18) {
        return ethers.utils.formatUnits(value, decimals);
    }
}

